import{_ as o,o as t,c as r,a2 as s}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"Hexo 블로그 임포트 — Research (Phase 0)","description":"","frontmatter":{"title":"Hexo 블로그 임포트 — Research (Phase 0)","feature_id":"008","created":"2026-06-02 15:10 (KST)","date":"2026-06-02T00:00:00.000Z"},"headers":[],"relativePath":"specs/008-hexo-blog-import/research.md","filePath":"specs/008-hexo-blog-import/research.md","lastUpdated":null}'),a={name:"specs/008-hexo-blog-import/research.md"};function c(i,e,d,l,n,g){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="research-hexo-→-vitepress-임포트" tabindex="-1">Research: Hexo → VitePress 임포트 <a class="header-anchor" href="#research-hexo-→-vitepress-임포트" aria-label="Permalink to &quot;Research: Hexo → VitePress 임포트&quot;">​</a></h1><p>스펙의 미해결 지점과 Technical Context 의 NEEDS CLARIFICATION 을 해소한 결과. 각 항목: <strong>Decision / Rationale / Alternatives</strong>.</p><h2 id="r1-구현-언어-—-node-js-단일-스크립트-ps-bash-페어-대신" tabindex="-1">R1. 구현 언어 — Node.js 단일 스크립트 (PS+Bash 페어 대신) <a class="header-anchor" href="#r1-구현-언어-—-node-js-단일-스크립트-ps-bash-페어-대신" aria-label="Permalink to &quot;R1. 구현 언어 — Node.js 단일 스크립트 (PS+Bash 페어 대신)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 임포터를 <strong>Node ESM 스크립트</strong>(<code>scripts/import-hexo-blog.mjs</code>, Node 내장 모듈만 사용)로 구현한다. 기존 <code>sync-*.{ps1,sh}</code> 의 PowerShell+Bash 페어 관례를 이 기능에서는 따르지 않는다.</li><li><strong>Rationale</strong>: 이 작업은 단순 파일 복사가 아니라 <strong>프런트매터 파싱 · Hexo 태그 정규식 변환 · include 재귀 전개 · 이미지 그래프 해석 · 사이드바(.mts) 생성</strong> 으로 이뤄진 텍스트 변환 파이프라인이다. 같은 로직을 PowerShell·Bash 두 벌로 유지하면 정규식·인코딩(UTF-8/BOM)·경로 처리에서 미묘한 불일치가 생기기 쉽다. 블로그는 이미 Node(VitePress) 툴체인을 쓰므로 추가 런타임이 없고, 한 벌의 크로스플랫폼 소스로 win32/POSIX 를 동시에 만족한다. 산출물(사이드바)이 <code>.mts</code> 라 Node 로 생성하는 편이 자연스럽다.</li><li><strong>Alternatives</strong>: (a) PS+Bash 페어 — 선례엔 맞지만 복잡 변환에 중복·버그 위험. (b) gray-matter 등 npm 의존 추가 — 의존 0 원칙을 위해 최소 YAML 파서를 손수 구현(필요 필드 title/date/categories/tags 만). (c) Hexo 자체 렌더 결과 (<code>db.json</code>/<code>public/</code>) 재사용 — 출력이 완성 HTML 이라 VitePress 마크다운 흐름과 안 맞고 테마 잔재가 섞임 → 기각.</li></ul><blockquote><p>스펙 Assumptions 의 &quot;PowerShell+Bash 페어&quot; 가정은 본 결정으로 대체한다.</p></blockquote><h2 id="r2-대상-섹션-경로·노출-형태-open-question-1-해소" tabindex="-1">R2. 대상 섹션 경로·노출 형태 (Open Question #1 해소) <a class="header-anchor" href="#r2-대상-섹션-경로·노출-형태-open-question-1-해소" aria-label="Permalink to &quot;R2. 대상 섹션 경로·노출 형태 (Open Question #1 해소)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 대상 섹션은 <code>/blog-archive/</code>. 진입 <code>index.md</code> 는 <strong>hero 없는 경량 아카이브 인덱스</strong>(카테고리 그룹 + 각 그룹 최신글 링크)로 만든다. cowork/hermes 식 <code>layout: home</code> hero 랜딩은 두지 않는다.</li><li><strong>Rationale</strong>: 옮겨오는 것은 과거 글 아카이브다. 마케팅형 랜딩보다 카테고리 내비게이션 + 최신순 목록이 독자 목적에 맞고, 사이드바 자동 생성과 일관된다. 추후 hero 가 필요하면 index.md 만 교체하면 되므로 비가역 결정이 아니다.</li><li><strong>Alternatives</strong>: hero 랜딩(과투자), 사이트 루트 흡수(기존 저널/명세와 혼선) → 기각. 단일 최상위 경로 <code>/blog-archive/</code> 로 기존 섹션과 충돌 회피.</li></ul><h2 id="r3-옛-url-리다이렉트-open-question-2-해소" tabindex="-1">R3. 옛 URL 리다이렉트 (Open Question #2 해소) <a class="header-anchor" href="#r3-옛-url-리다이렉트-open-question-2-해소" aria-label="Permalink to &quot;R3. 옛 URL 리다이렉트 (Open Question #2 해소)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 옛 Hexo permalink(<code>:title/</code>)→새 경로 301 리다이렉트는 <strong>이번 범위 밖</strong>으로 확정(보류). 새 글 경로는 <code>/blog-archive/&lt;category&gt;/&lt;slug&gt;</code> 로 안정화하고, 필요 시 후속 기능에서 GitHub Pages <code>_redirects</code>/메타 리다이렉트로 처리한다.</li><li><strong>Rationale</strong>: 원본 사이트(goodsaem.github.io)와 신규 사이트(<code>/blog/</code> base)는 도메인·base 가 달라 단순 동치 리다이렉트가 성립하지 않는다. 트래픽 이전 요구가 확인된 뒤 다루는 게 합리적.</li></ul><h2 id="r4-hexo-태그-→-vitepress-변환-규칙" tabindex="-1">R4. Hexo 태그 → VitePress 변환 규칙 <a class="header-anchor" href="#r4-hexo-태그-→-vitepress-변환-규칙" aria-label="Permalink to &quot;R4. Hexo 태그 → VitePress 변환 규칙&quot;">​</a></h2><p><code>source/_data/fa-classes.json</code> 과 실제 사용 패턴을 근거로 확정. 상세 표는 <a href="./contracts/transform-rules">contracts/transform-rules.md</a>.</p><ul><li><strong><code>{% asset_img name.ext [alt] %}</code> (261)</strong> → 자산을 글별 <code>.assets/</code> 로 복사 후 <code>![alt](./&lt;slug&gt;.assets/name.ext)</code> 상대 링크. VitePress 가 상대 이미지 링크를 번들하므로 <code>public/</code> 강제 없이 동작.</li><li><strong><code>{% fa icon [size] %}</code> / <code>{% fa_all_free_class %}</code> (72)</strong> → 아이콘명을 이모지로 매핑(home→🏠, user→👤, …), 미매핑은 제거(빈 문자열). FA CSS 를 사이트에 들이지 않기 위함. size 인자(<code>2x</code> 등)는 무시.</li><li><strong><code>{% callout type:&quot;X&quot; title:&quot;T&quot; %}…{% endcallout %}</code> (11쌍)</strong> → VitePress 컨테이너. <code>info→::: tip</code>, <code>warning→::: warning</code>, <code>danger→::: danger</code>, <code>success→::: tip</code>. title 은 컨테이너 제목 인자로.</li><li><strong><code>{% iframe src [w] [h] %}</code> (1)</strong> → <code>&lt;iframe src=&quot;…&quot; width=… height=… loading=&quot;lazy&quot;&gt;&lt;/iframe&gt;</code>.</li><li><strong><code>{% drawio file %}</code> (3)</strong> → 동일 이름 렌더 이미지(png/svg)가 있으면 이미지로, 없으면 원본 <code>.drawio</code> 를 자산 복사 후 다운로드 링크 + 안내.</li><li><strong><code>{% incl &lt;name&gt; %}</code> (16)</strong> → <code>source/_includes/&lt;name&gt;.md</code> 내용을 그 자리에 재귀 인라인(깊이 가드 8). 미발견 시 빈 처리 + 리포트.</li><li><strong><code>{% raw %}…{% endraw %}</code></strong> → 래퍼 제거(내용 그대로).</li><li><strong>잔여 미지 태그</strong> → 안전 제거 + 리포트 집계(SC-8: 출력에 <code>{% %}</code> 0건).</li></ul><h2 id="r5-vue-mdx-빌드-안전성" tabindex="-1">R5. Vue/MDX 빌드 안전성 <a class="header-anchor" href="#r5-vue-mdx-빌드-안전성" aria-label="Permalink to &quot;R5. Vue/MDX 빌드 안전성&quot;">​</a></h2><ul><li><strong>Decision</strong>: 본문 텍스트의 <code>{{ … }}</code>(코드펜스/인라인코드 밖)는 <code>&lt;span v-pre&gt;{{ … }}&lt;/span&gt;</code> 로 감싸거나 <code>&amp;#123;&amp;#123;</code> 로 이스케이프. 인라인 코드는 config.mts 가 이미 <code>v-pre</code> 처리하므로 그대로 둠. HTML 처럼 보이는 미닫힘 <code>&lt;word&gt;</code> 토큰(예: <code>&lt;param&gt;</code>)은 코드펜스 밖이면 이스케이프.</li><li><strong>Rationale</strong>: VitePress=Vue. <code>{{var}}</code>·정체불명 <code>&lt;Tag&gt;</code> 가 컴파일 에러를 일으켜 strict 빌드를 깬다(FR-7). 달력 글의 <code>&lt;style&gt;</code>/<code>&lt;table&gt;</code> 등 정상 HTML 은 VitePress 가 허용하므로 보존.</li><li><strong>Alternatives</strong>: 전 페이지 <code>&lt;!-- v-pre 비활성 --&gt;</code> 불가. 페이지 전체를 코드블록화 → 렌더 깨짐. → 토큰 단위 이스케이프 채택.</li></ul><h2 id="r6-카테고리-→-영문-라벨-매핑-fr-6" tabindex="-1">R6. 카테고리 → 영문 라벨 매핑 (FR-6) <a class="header-anchor" href="#r6-카테고리-→-영문-라벨-매핑-fr-6" aria-label="Permalink to &quot;R6. 카테고리 → 영문 라벨 매핑 (FR-6)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 폴더 경로/<code>categories</code> 를 그룹 키로 쓰고, 스크립트 상단의 명시적 매핑표로 영문 라벨 부여. 예: <code>coding→Coding</code>, <code>coding/java→Java</code>, <code>coding/jhipster→JHipster</code>, <code>coding/springboot→Spring Boot</code>, <code>setup→Setup</code>, <code>tool→Tools</code>, <code>app→Apps</code>, <code>blog→Blog</code>, 한글값(예: <code>코딩→Coding</code>). 매핑 없는 값은 슬러그를 Title Case 음역. 빈 값은 <code>Uncategorized</code>.</li><li><strong>Rationale</strong>: 사용자 결정(한글 메뉴 라벨→영문). 명시적 표라 예측 가능하고 재실행 안정적. 사이드바·내비 라벨 전부 영문 통일.</li></ul><h2 id="r7-멱등-재실행-사이드바-내비-등록-fr-8-fr-9" tabindex="-1">R7. 멱등 재실행 &amp; 사이드바/내비 등록 (FR-8/FR-9) <a class="header-anchor" href="#r7-멱등-재실행-사이드바-내비-등록-fr-8-fr-9" aria-label="Permalink to &quot;R7. 멱등 재실행 &amp; 사이드바/내비 등록 (FR-8/FR-9)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 매 실행 시 <code>blog-archive/**</code> 와 <code>.vitepress/blog-archive- sidebar.mts</code> 를 <strong>전량 삭제 후 재생성</strong>(생성물은 git 추적). config.mts 의 import·spread·nav 3개 지점은 <strong>마커 주석 블록</strong>(<code>/* SPECKIT:blog-archive ... */</code>) 사이를 정규식으로 치환해 멱등 주입하고, 마커가 없으면 최초 1회 삽입.</li><li><strong>Rationale</strong>: 전량 재생성으로 고아 파일 0(SC-4). 마커 치환으로 config.mts 수동 편집과 충돌 없이 재실행 안전. cowork/hermes 의 수동 <code>...coworkSidebar</code> 스프레드 패턴과 형태 동일.</li><li><strong>Alternatives</strong>: config.mts 전체 생성(다른 섹션 설정 파괴) → 기각. 수동 3줄 배선(선례엔 맞지만 FR-8 &quot;등록&quot; 자동화 약화) → 마커 자동주입 + 수동 폴백 문서화.</li></ul><h2 id="r8-프런트매터-변환" tabindex="-1">R8. 프런트매터 변환 <a class="header-anchor" href="#r8-프런트매터-변환" aria-label="Permalink to &quot;R8. 프런트매터 변환&quot;">​</a></h2><ul><li><strong>Decision</strong>: 출력 프런트매터에 <code>title</code>, <code>date</code>(원본 시각 ISO 보존), <code>tags</code> (있으면), <code>editLink: false</code>, <code>lastUpdated: false</code> 를 둔다. <code>categories</code> 는 그룹핑·사이드바 생성에만 쓰고 프런트매터엔 선택적으로 남긴다. 본 저장소 규칙대로 목록·사이드바는 <code>date</code> 내림차순(최신 먼저).</li><li><strong>Rationale</strong>: VitePress 는 자동 정렬을 안 하므로 인덱스·사이드바를 스크립트가 정렬 생성. <code>editLink/lastUpdated</code> 비활성으로 임포트 글에 부정확한 &quot;수정일/소스 편집&quot; 링크가 붙지 않게 함.</li></ul>',20)])])}const p=o(a,[["render",c]]);export{u as __pageData,p as default};
